exports.push([module.id, "\n.el-dialog {\r\nborder-radius: 10px;\r\noverflow: hidden;\n}\r\n", "", {"version":3,"sources":["D:/laragon/www/sdrimsac-tenant/resources/js/views/item_sets/resources/js/views/item_sets/form.vue"],"names":[],"mappings":";AA8bA;AACA,oBAAA;AACA,iBAAA;CACA","file":"form.vue","sourcesContent":["<template>\r\n    <el-dialog\r\n        width=\"65%\"\r\n        :title=\"titleDialog\"\r\n        :visible=\"showDialog\"\r\n        :close-on-click-modal=\"false\"\r\n        @close=\"close\"\r\n        @open=\"create\"\r\n        append-to-body\r\n        top=\"7vh\"\r\n        class=\"rounded-dialog\"\r\n    >\r\n        <form autocomplete=\"off\" @submit.prevent=\"submit\">\r\n            <div class=\"form-body\">\r\n                <br>\r\n                <div class=\"row\">\r\n                    <div class=\"short-div col-md-2\">\r\n                                    <div class=\"form-group\" :class=\"{'has-danger': errors.internal_id}\">\r\n                                        <label class=\"control-label\">\r\n                                            \r\n                                            Código Interno\r\n                                            <el-tooltip\r\n                                                class=\"item\"\r\n                                                effect=\"dark\"\r\n                                                content=\"Código interno de la empresa para el control de sus productos\"\r\n                                                placement=\"top-start\"\r\n                                              >\r\n                                                <i class=\"fa fa-info-circle\"></i>\r\n                                            </el-tooltip>\r\n                                        </label>\r\n                                        \r\n                                        <el-input\r\n                                            v-model=\"form.internal_id\"\r\n                     